/**
 *  设置缓存
 * @param {*} key 保存键
 * @param {*} value 保存内容 localSorage 不能保存 Object 对象 需要使用 stringify 进行转换
 * @param {*} expired 失效时间 定义 单位 分钟 默认一年
 */
export const set = <T>(key: string, value: T, expired: number = 60 * 24 * 365): void => {
  /* 定义 source 临时 对象 临时存储 key value 赋值后 加入到 localStorage */
  const source: { key: string; value?: string } = { key };
  /* now 获取当前时间 */
  const now = Date.now();
  /* 1 分钟计算 (1000*60)  计算出总失效时间 (1000 * 60 * expired) now + 失效总分钟 算出最大存储时间 */
  if (expired) {
    source.value = JSON.stringify({ data: value, expired: now + 1000 * 60 * expired });
  } else {
    source.value = JSON.stringify({ data: value, expired: now + 1000 * 60 });
  }
  localStorage.setItem(source.key, source.value);
};
/**
 * 获取Source
 * @param {*} key key
 */
export function getSource<T>(key: string): T {
  const now = Date.now();
  const source = { key, value: null };
  /* 获取 localStorage 存储信息 赋值给 source 对象 */
  source.value = JSON.parse(localStorage.getItem(source.key));

  /* 如果key 有效  判断当前时间 是否超过 失效时间 */
  if (source.value) {
    if (now >= source.value.expired) {
      /* 超过失效时间 删除 储存内容  */
      remove(source.key);
    } else {
      return source.value;
    }
  }
}

/**
 * 获取值
 * @param {*} key key
 */
export function get(key) {
  const source = getSource<{ data: string }>(key);
  return source && source.data;
}

/**
 * 删除缓存
 * @param {*} key 缓存key
 */
export function remove(key: string): void {
  localStorage.removeItem(key);
}

export default { remove, set, get, getSource };
